        return true
    }
    
    @available(iOS 9.0, *)
    func setAllowArbitraryLoads(forHost host: URL, fromInfoDict infoDict: [String: String]) throws {
        guard let subdomain = host.host else { return }
        
        for key in infoDict.keys where key.hasPrefix("NSAppTransportSecurity") {
            var dict = infoDict[key] ?? [:]
            
            if !dict.contains(where: { $0.key == "NSTemporaryExemptions" }) {
                dict["NSTemporaryExemptions"] = "\(subdomain)"
                
                let modifiedInfo = [key: try JSONSerialization.jsonObject(with: try JSONSerialization.data(withJSONObject: dict)) as? [String: Any] ?? [:]]
                Bundle.main.infoDictionary?.updateValue(modifiedInfo, forKey: key)
            }
        }
    }
